select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.badges as b, postgres.users as u where u.id = c.userid and u.id = p.owneruserid and u.id = ph.userid and u.id = b.userid and c.creationdate>=timestamp '2010-07-31 05:18:59' and c.creationdate<=timestamp '2014-09-12 07:59:13' and p.score>=-2 and p.viewcount>=0 and p.viewcount<=18281 and ph.posthistorytypeid=2 and b."date">=timestamp '2010-10-20 08:33:44' and u.views>=0 and u.views<=75;
